function processData(input) {
  try {
    // Agent yanıtını parse et
    let requestAnalysis;
    if (typeof input.content === 'string') {
      // JSON string ise parse et
      try {
        requestAnalysis = JSON.parse(input.content);
      } catch (e) {
        // JSON parse edilemezse metin olarak kullan
        requestAnalysis = {
          dersKonusu: 'Genel',
          zorlukSeviyesi: 'Orta',
          talepTuru: 'konu-aciklama'
        };
      }
    } else {
      requestAnalysis = input.content;
    }

    // Talep türünü belirle
    const requestType = requestAnalysis.talepTuru || requestAnalysis.talepTürü || 'konu-aciklama';

    return {
      requestType: requestType.toLowerCase().replace(' ', '-'),
      subject: requestAnalysis.dersKonusu || requestAnalysis.konu || 'Genel',
      level: requestAnalysis.zorlukSeviyesi || requestAnalysis.seviye || 'Orta',
      analysis: requestAnalysis
    };
  } catch (error) {
    return {
      requestType: 'konu-aciklama',
      subject: 'Genel',
      level: 'Orta',
      analysis: {
        dersKonusu: 'Genel',
        zorlukSeviyesi: 'Orta',
        talepTuru: 'konu-aciklama'
      },
      error: error.message
    };
  }
}

function processData(input) {
  // Gelen yanıtı al
  const content = input.content || 'İçerik oluşturulamadı';
  const subject = input.subject || 'Genel Konu';
  const level = input.level || 'Orta Seviye';

  // İçerik türünü belirle
  let contentType = 'Konu Açıklaması';
  if (content.includes('Soru') && content.includes('Çözüm')) {
    contentType = 'Soru Çözümü';
  } else if (content.includes('Özet') || content.includes('Ana Hatlar')) {
    contentType = 'Konu Özeti';
  } else if (content.includes('Test') || content.includes('Quiz') || content.includes('Soru 1')) {
    contentType = 'Test';
  }

  // Ek kaynaklar öner
  const additionalResources = generateAdditionalResources(subject, level);

  // İçeriği formatla
  const formattedContent = `
    # ${subject} - ${contentType}
    ## Seviye: ${level}

    ${content}

    ## Ek Kaynaklar
    ${additionalResources.join('\n    ')}
  `;

  return {
    formattedContent,
    subject,
    level,
    contentType,
    timestamp: new Date().toISOString()
  };
}

// Ek kaynaklar öner
function generateAdditionalResources(subject, level) {
  const resources = [
    '📚 Konu ile ilgili kitap önerileri',
    '🔗 Online eğitim platformları',
    '📝 Alıştırma kaynakları',
    '🎬 Video dersler'
  ];

  return resources;
}
